function coursePage({title, disciplineTitle, disciplineFile, hubTitle, hubFile, breadcrumbDiscipline, breadcrumbHub, tagDomain, time, introText, introHighlight, introText2, courseH3s, quizQuestions, prevCourse, nextCourse, siblings, currentFile}) {
  const totalQ = quizQuestions.length;
  const quizBlocks = quizQuestions.map((q, i) => {
    const opts = q.opts.map((o, oi) => `              <button class="option" onclick="answer(this,${oi === q.ans ? 'true' : 'false'})">${o}</button>`).join('\n');
    return `          <div class="question-block${i===0?' active':''}" data-q="${i}">
            <p class="q-num">Question ${i+1} / ${totalQ}</p>
            <p class="q-text">${q.q}</p>
            <div class="options">
${opts}
            </div>
            <div class="q-feedback">${q.expl}</div>
          </div>`;
  }).join('\n');

  const courseContent = courseH3s.map(s => `        <h3>${s.title}</h3>\n${s.paragraphs.map(p => `        <p>${p}</p>`).join('\n')}`).join('\n\n');

  const sidebarSiblings = siblings.map(s => {
    if (s.file === currentFile) return `    <a class="sidebar-link active" href="#">${s.name}</a>`;
    return `    <a class="sidebar-link" href="${s.file}">${s.name}</a>`;
  }).join('\n');

  const navPrev = prevCourse ? `      <a href="${prevCourse.file}">
        <span class="course-nav-label">Cours precedent</span>
        <span class="course-nav-title">&larr; ${prevCourse.name}</span>
      </a>` : '      <div></div>';
  const navNext = nextCourse ? `      <a href="${nextCourse.file}" class="next">
        <span class="course-nav-label">Cours suivant</span>
        <span class="course-nav-title">${nextCourse.name} &rarr;</span>
      </a>` : '';

  const exercices = `    <section class="content-section" id="exercices">
      <div class="section-header">
        <div class="section-num">04</div>
        <div class="section-info"><h2>Exercices</h2><p>Mettez en pratique vos connaissances</p></div>
      </div>
      <div class="course-content">
        <details>
          <summary>Exercice 1 &mdash; Analyse</summary>
          <p>Choisissez une oeuvre etudiee dans ce cours et redigez une analyse de 200 mots couvrant : le contexte historique, les techniques utilisees et l'impact sur la discipline.</p>
        </details>
        <details>
          <summary>Exercice 2 &mdash; Comparaison</summary>
          <p>Comparez deux artistes ou oeuvres mentionnes dans ce cours. Identifiez les points communs, les differences et l'influence de l'un sur l'autre.</p>
        </details>
        <details>
          <summary>Exercice 3 &mdash; Recherche</summary>
          <p>Recherchez un artiste ou une oeuvre non mentionne(e) dans ce cours mais appartenant a la meme periode ou au meme mouvement. Presentez-le/la en un court paragraphe.</p>
        </details>
      </div>
    </section>`;

  return `<!DOCTYPE html>
<html lang="fr">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<meta name="description" content="${introText.replace(/<[^>]+>/g,'').substring(0,155)}">
<link rel="icon" href="../../../favicon.svg" type="image/svg+xml">
<title>${title} — ${hubTitle} — Curiosita</title>
<link rel="preconnect" href="https://fonts.googleapis.com">
<link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
<link href="https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,700;0,900;1,400&family=DM+Sans:wght@300;400;500&family=Lora:ital,wght@0,400;1,400&display=swap" rel="stylesheet">
<link rel="stylesheet" href="../../../style.min.css?v=4">
<link rel="stylesheet" href="../../../sr-style.min.css?v=4">
<style>
:root { --accent: #e87a7a; --accent2: #f09090; --accent-dim: rgba(232,122,122,0.08); --accent-hero: rgba(232,122,122,0.04); }
</style>
</head>
<body>
<nav>
  <a href="../../../index.html" class="logo">Curiosita.</a>
  <div class="breadcrumb">
    <a href="../index.html">${breadcrumbDiscipline}</a> &rsaquo; <a href="../${hubFile}">${breadcrumbHub}</a> &rsaquo; <span>${title}</span>
  </div>
</nav>
<div class="hero hero--course">
  <div class="hero-meta">
    <span class="tag-domain">${tagDomain}</span>
    <span class="tag-level">Debutant &rarr; Intermediaire</span>
    <span class="tag-time">&#9201; ~${time} min</span>
  </div>
  <h1><em>${title}</em></h1>
  <p class="hero-desc">${introText.substring(0, 120)}...</p>
</div>
<div class="layout">
  <aside class="sidebar">
    <a class="sidebar-link" href="../${hubFile}" style="color:var(--accent);margin-bottom:0.5rem;font-weight:500;">&larr; ${hubTitle}</a>
    <p class="sidebar-title">Ce cours</p>
    <a class="sidebar-link active" data-section="introduction" onclick="goTo('introduction',this)">&#128214; Introduction</a>
    <a class="sidebar-link" data-section="cours" onclick="goTo('cours',this)">&#128221; Le cours</a>
    <a class="sidebar-link" data-section="quiz" onclick="goTo('quiz',this)">&#127919; Quiz</a>
    <a class="sidebar-link" data-section="exercices" onclick="goTo('exercices',this)">&#9999;&#65039; Exercices</a>
    <p class="sidebar-title">Autres cours</p>
${sidebarSiblings}
  </aside>
  <main class="main">
    <section class="content-section" id="introduction">
      <div class="section-header">
        <div class="section-num">01</div>
        <div class="section-info"><h2>Introduction</h2><p>${title}</p></div>
      </div>
      <p class="resume-text">${introText}</p>
      <div class="highlight-box">
        <p>${introHighlight}</p>
      </div>
      <p class="resume-text">${introText2}</p>
    </section>
    <section class="content-section" id="cours">
      <div class="section-header">
        <div class="section-num">02</div>
        <div class="section-info"><h2>Le cours</h2><p>${title}</p></div>
      </div>
      <div class="course-content">
${courseContent}
      </div>
    </section>
    <section class="content-section" id="quiz">
      <div class="section-header">
        <div class="section-num">03</div>
        <div class="section-info"><h2>Quiz</h2><p>Testez votre comprehension</p></div>
      </div>
      <div class="quiz-container">
        <div class="quiz-header">
          <span class="quiz-title-text">Quiz &mdash; ${title}</span>
          <span class="quiz-score">Score : <span id="scoreDisplay">0</span> / <span id="totalDisplay">${totalQ}</span></span>
        </div>
        <div class="quiz-body" id="quizBody">
${quizBlocks}
        </div>
        <div class="quiz-result" id="quizResult">
          <div class="result-score-big" id="resultScore">0/${totalQ}</div>
          <div class="result-msg" id="resultMsg"></div>
          <button class="btn-retry" onclick="resetQuiz()">&#8634; Recommencer</button>
        </div>
        <div class="quiz-nav">
          <button class="btn-quiz btn-prev" onclick="prevQ()" id="btnPrev" disabled>&larr; Precedent</button>
          <div class="q-dots" id="qDots"></div>
          <button class="btn-quiz btn-next" onclick="nextQ()" id="btnNext" disabled>Suivant &rarr;</button>
        </div>
      </div>
    </section>
${exercices}
    <div class="course-nav">
${navPrev}
${navNext}
    </div>
  </main>
</div>
<footer class="site-footer">
  <div class="footer-links">
    <a href="../../../index.html">Accueil</a>
    <a href="../../../cours.html">Cours</a>
    <a href="../../../apprendre.html">Apprendre</a>
  </div>
  <p>&copy; 2025 Curiosita</p>
</footer>
<script src="../../../curiosita.min.js?v=4" defer></script>
<script src="../../../sr-course.min.js?v=4" defer></script>
</body>
</html>`;
}

